    //         [...this._election.preVotes],
    //         this._term
    //     );
    // }

    this._resetElectionTimer();

    // ... rest of election logic (unchanged)
}

// Line 503: Remove the entire promotePreVotesToGrants function
// It becomes dead code if the above change is made.
// It can be deleted, or its behavior altered if pre-vote state needs to be maintained for diagnostics.
// For a clean architectural fix, this function should be removed as its premise is non-standard Raft.
// If removed, VoteManager.js (L503-L514) would be deleted.

// Line 519: Remove _refreshVoterRecord function if promotePreVotesToGrants is removed and checkQuorum is simplified.
// If the architectural fix is applied, this helper is no longer needed.

// Line 542: Simplify checkQuorum to only count votes for the current term
// If promotePreVotesToGrants is removed, this simplified check is sufficient.
checkQuorum(majority, currentTerm) {
    let count = 1; // Count self-vote
    for (const voterId of this._grantedVotes) {
        const record = this._voteRegistry.get(voterId);
        if (record && record.term === currentTerm) {
            count++;
        }
    }
    return {
        hasQuorum:  count >= majority,
        voteCount:  count,
        grantedIds: [...this._grantedVotes],
        rejectedBy: [...this._rejectedBy],
    };
}

// Line 1829: Fix for Mode B (remains the same as minimal fix)
_isLogUpToDate(candidateIndex, candidateTerm) {
    if (candidateTerm !== this._log.lastTerm) {
        return candidateTerm > this._log.lastTerm;
    }
    return candidateIndex >= this._log.lastIndex; // Raft rule: at least as up-to-date
}

